<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu-ish Desktop</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { width: 100%; height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", system-ui, sans-serif;
    color: #f2f0ee;
    user-select: none;
  }

  #desktop {
    position: absolute;
    inset: 0;
    background:
      radial-gradient(circle at 25% 20%, #5a2d4a 0%, transparent 55%),
      radial-gradient(circle at 80% 80%, #3d1f30 0%, transparent 55%),
      linear-gradient(135deg, #2c001e 0%, #48173a 50%, #77216f 100%);
    overflow: hidden;
  }

  /* Taskbar / dock — left vertical bar, Ubuntu style */
  #taskbar {
    position: absolute;
    top: 0; left: 0; bottom: 0;
    width: 66px;
    background: rgba(20, 10, 18, 0.82);
    backdrop-filter: blur(6px);
    border-right: 1px solid rgba(255,255,255,0.08);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding-top: 12px;
    gap: 10px;
    z-index: 500;
  }
  .launcher {
    width: 48px;
    height: 48px;
    border-radius: 12px;
    border: none;
    cursor: pointer;
    color: #fff;
    font-size: 22px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: linear-gradient(160deg, #e95420, #c7431a);
    box-shadow: 0 2px 6px rgba(0,0,0,0.4);
    transition: transform .12s ease, filter .12s ease;
  }
  .launcher:hover { transform: translateY(-2px); filter: brightness(1.12); }
  .launcher.files { background: linear-gradient(160deg, #4a7dc4, #345f9c); }
  .launcher .label {
    position: absolute;
    left: 74px;
    background: rgba(0,0,0,0.8);
    padding: 3px 8px;
    border-radius: 5px;
    font-size: 12px;
    white-space: nowrap;
    opacity: 0;
    pointer-events: none;
    transition: opacity .12s;
  }
  .launcher:hover .label { opacity: 1; }

  /* Top bar */
  #topbar {
    position: absolute;
    top: 0; left: 66px; right: 0;
    height: 28px;
    background: rgba(10, 5, 9, 0.7);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 14px;
    font-size: 13px;
    z-index: 400;
  }

  /* Windows */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    width: 620px;
    height: 440px;
    background: #2b2b2b;
    border: 1px solid rgba(255,255,255,0.12);
    border-radius: 10px;
    box-shadow: 0 18px 50px rgba(0,0,0,0.55);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .window.open { display: flex; }
  .titlebar {
    height: 38px;
    background: linear-gradient(180deg, #3a3a3a, #303030);
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: move;
    border-bottom: 1px solid rgba(0,0,0,0.4);
    flex: 0 0 auto;
  }
  .titlebar .title { font-size: 13px; font-weight: 600; flex: 1; }
  .win-btn {
    width: 22px; height: 22px;
    border-radius: 50%;
    border: none;
    margin-left: 6px;
    cursor: pointer;
    font-size: 12px;
    color: #2b2b2b;
    display: flex; align-items: center; justify-content: center;
  }
  .win-close { background: #e95420; color: #fff; }
  .win-close:hover { filter: brightness(1.15); }
  .win-body { flex: 1 1 auto; display: flex; flex-direction: column; min-height: 0; }

  /* Files app */
  #files-window .toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #262626;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }
  #files-up {
    background: #3d3d3d;
    color: #fff;
    border: 1px solid rgba(255,255,255,0.12);
    border-radius: 6px;
    padding: 5px 10px;
    cursor: pointer;
    font-size: 14px;
  }
  #files-up:hover { background: #4a4a4a; }
  #files-path {
    flex: 1;
    background: #1e1e1e;
    padding: 6px 10px;
    border-radius: 6px;
    font-family: "Ubuntu Mono", monospace;
    font-size: 13px;
    color: #b6d7ff;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  #files-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 8px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
    padding: 10px 6px;
    border-radius: 8px;
    cursor: default;
    text-align: center;
    font-size: 12.5px;
    word-break: break-word;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item .ico { font-size: 30px; line-height: 1; }
  .fs-item.folder { cursor: pointer; }

  /* Notepad app */
  #tabs {
    display: flex;
    align-items: stretch;
    background: #262626;
    border-bottom: 1px solid rgba(255,255,255,0.06);
    overflow-x: auto;
    flex: 0 0 auto;
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 8px 12px;
    font-size: 13px;
    cursor: pointer;
    border-right: 1px solid rgba(255,255,255,0.06);
    color: #cfcfcf;
    white-space: nowrap;
    max-width: 180px;
  }
  .tab.active { background: #1e1e1e; color: #fff; }
  .tab .tab-name { overflow: hidden; text-overflow: ellipsis; }
  .tab .tab-close {
    font-size: 14px;
    line-height: 1;
    padding: 0 3px;
    border-radius: 3px;
    color: #999;
  }
  .tab .tab-close:hover { background: rgba(255,255,255,0.15); color: #fff; }
  #new-tab {
    background: none;
    border: none;
    color: #fff;
    font-size: 18px;
    padding: 0 14px;
    cursor: pointer;
    flex: 0 0 auto;
  }
  #new-tab:hover { background: rgba(255,255,255,0.08); }
  #editor {
    flex: 1;
    width: 100%;
    resize: none;
    border: none;
    outline: none;
    background: #1e1e1e;
    color: #eaeaea;
    padding: 14px;
    font-family: "Ubuntu Mono", "Consolas", monospace;
    font-size: 14px;
    line-height: 1.5;
    user-select: text;
  }
</style>
</head>
<body>
<div id="desktop">

  <div id="taskbar">
    <button id="open-files" class="launcher files" title="Files">
      🗂️<span class="label">Files</span>
    </button>
    <button id="open-notepad" class="launcher" title="Notepad">
      📝<span class="label">Notepad</span>
    </button>
  </div>

  <div id="topbar">
    <span>Activities</span>
    <span id="clock"></span>
    <span>⏻</span>
  </div>

  <!-- Files window -->
  <div id="files-window" class="window" style="left:180px; top:90px;">
    <div class="titlebar">
      <span class="title">Files</span>
      <button class="win-btn win-close" data-target="files-window">✕</button>
    </div>
    <div class="win-body">
      <div class="toolbar">
        <button id="files-up">⬆ Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad window -->
  <div id="notepad-window" class="window" style="left:300px; top:140px;">
    <div class="titlebar">
      <span class="title">Notepad</span>
      <button class="win-btn win-close" data-target="notepad-window">✕</button>
    </div>
    <div class="win-body">
      <div id="tabs"></div>
      <textarea id="editor" spellcheck="false" placeholder="Start typing…"></textarea>
    </div>
  </div>

</div>

<script>
(function () {
  "use strict";

  /* ---------- Window open/close + drag ---------- */
  function openWindow(id) {
    var w = document.getElementById(id);
    w.classList.add("open");
    // bring to front
    document.querySelectorAll(".window").forEach(function (el) { el.style.zIndex = 100; });
    w.style.zIndex = 200;
  }
  function closeWindow(id) {
    document.getElementById(id).classList.remove("open");
  }

  document.getElementById("open-files").addEventListener("click", function () { openWindow("files-window"); });
  document.getElementById("open-notepad").addEventListener("click", function () { openWindow("notepad-window"); });

  document.querySelectorAll(".win-close").forEach(function (btn) {
    btn.addEventListener("click", function () { closeWindow(btn.dataset.target); });
  });

  // Make windows draggable by their titlebar
  document.querySelectorAll(".window").forEach(function (win) {
    var bar = win.querySelector(".titlebar");
    var dragging = false, ox = 0, oy = 0;
    win.addEventListener("mousedown", function () {
      document.querySelectorAll(".window").forEach(function (el) { el.style.zIndex = 100; });
      win.style.zIndex = 200;
    });
    bar.addEventListener("mousedown", function (e) {
      if (e.target.classList.contains("win-btn")) return;
      dragging = true;
      var r = win.getBoundingClientRect();
      ox = e.clientX - r.left;
      oy = e.clientY - r.top;
      e.preventDefault();
    });
    document.addEventListener("mousemove", function (e) {
      if (!dragging) return;
      var x = Math.max(66, Math.min(window.innerWidth - 80, e.clientX - ox));
      var y = Math.max(28, Math.min(window.innerHeight - 60, e.clientY - oy));
      win.style.left = x + "px";
      win.style.top = y + "px";
    });
    document.addEventListener("mouseup", function () { dragging = false; });
  });

  /* ---------- Clock ---------- */
  function tick() {
    var d = new Date();
    var el = document.getElementById("clock");
    if (el) el.textContent = d.toLocaleDateString() + "  " +
      d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  }
  tick();
  setInterval(tick, 1000 * 30);

  /* ---------- Files app: fake filesystem ---------- */
  var FS = {
    "bin": { type: "folder", children: {
      "bash": { type: "file" }, "ls": { type: "file" }, "cat": { type: "file" },
      "grep": { type: "file" }, "python3": { type: "file" }
    }},
    "etc": { type: "folder", children: {
      "hostname": { type: "file" }, "hosts": { type: "file" },
      "passwd": { type: "file" }, "fstab": { type: "file" }
    }},
    "home": { type: "folder", children: {
      "user": { type: "folder", children: {
        "Documents": { type: "folder", children: {
          "resume.pdf": { type: "file" }, "notes.txt": { type: "file" },
          "budget.xlsx": { type: "file" }
        }},
        "Downloads": { type: "folder", children: {
          "ubuntu.iso": { type: "file" }, "photo.jpg": { type: "file" }
        }},
        "Pictures": { type: "folder", children: {
          "wallpaper.png": { type: "file" }, "screenshot.png": { type: "file" }
        }},
        ".bashrc": { type: "file" },
        "todo.txt": { type: "file" }
      }}
    }},
    "usr": { type: "folder", children: {
      "bin": { type: "folder", children: { "gcc": { type: "file" }, "node": { type: "file" } } },
      "lib": { type: "folder", children: {} },
      "share": { type: "folder", children: { "doc": { type: "folder", children: {} } } }
    }},
    "var": { type: "folder", children: {
      "log": { type: "folder", children: { "syslog": { type: "file" }, "auth.log": { type: "file" } } },
      "tmp": { type: "folder", children: {} },
      "www": { type: "folder", children: { "index.html": { type: "file" } } }
    }}
  };

  var currentPath = []; // array of segment names

  function nodeAt(pathArr) {
    var node = { type: "folder", children: FS };
    for (var i = 0; i < pathArr.length; i++) {
      if (!node.children || !node.children[pathArr[i]]) return null;
      node = node.children[pathArr[i]];
    }
    return node;
  }

  function renderFiles() {
    var pathStr = "/" + currentPath.join("/");
    document.getElementById("files-path").textContent = pathStr === "/" ? "/" : pathStr;

    var node = nodeAt(currentPath);
    var list = document.getElementById("files-list");
    list.innerHTML = "";
    if (!node || !node.children) return;

    var names = Object.keys(node.children).sort(function (a, b) {
      var fa = node.children[a].type === "folder", fb = node.children[b].type === "folder";
      if (fa !== fb) return fa ? -1 : 1;
      return a.localeCompare(b);
    });

    names.forEach(function (name) {
      var entry = node.children[name];
      var isFolder = entry.type === "folder";
      var item = document.createElement("div");
      item.className = "fs-item" + (isFolder ? " folder" : "");
      item.innerHTML = '<span class="ico">' + (isFolder ? "📁" : "📄") + '</span>' +
                       '<span class="fs-name"></span>';
      item.querySelector(".fs-name").textContent = name;
      if (isFolder) {
        item.addEventListener("dblclick", function () {
          currentPath.push(name);
          renderFiles();
        });
      }
      list.appendChild(item);
    });
  }

  document.getElementById("files-up").addEventListener("click", function () {
    if (currentPath.length > 0) {
      currentPath.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ---------- Notepad app ---------- */
  var STORE_KEY = "ubuntu_notepad_v1";
  var state = { tabs: [], active: null };

  function load() {
    try {
      var raw = localStorage.getItem(STORE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs)) state = parsed;
      }
    } catch (e) {}
    if (!state.tabs || state.tabs.length === 0) {
      var id = uid();
      state.tabs = [{ id: id, name: "Untitled", content: "" }];
      state.active = id;
    }
    if (!state.active || !state.tabs.some(function (t) { return t.id === state.active; })) {
      state.active = state.tabs[0].id;
    }
  }
  function save() {
    try { localStorage.setItem(STORE_KEY, JSON.stringify(state)); } catch (e) {}
  }
  function uid() {
    return "t" + Math.random().toString(36).slice(2, 9) + (state.tabs.length);
  }

  function activeTab() {
    return state.tabs.find(function (t) { return t.id === state.active; });
  }

  function renderTabs() {
    var strip = document.getElementById("tabs");
    strip.innerHTML = "";
    state.tabs.forEach(function (t) {
      var tab = document.createElement("div");
      tab.className = "tab" + (t.id === state.active ? " active" : "");
      tab.dataset.id = t.id;
      var nameSpan = document.createElement("span");
      nameSpan.className = "tab-name";
      nameSpan.textContent = t.name || "Untitled";
      tab.appendChild(nameSpan);
      var close = document.createElement("span");
      close.className = "tab-close";
      close.textContent = "✕";
      close.addEventListener("click", function (e) {
        e.stopPropagation();
        closeTab(t.id);
      });
      tab.appendChild(close);
      tab.addEventListener("click", function () {
        state.active = t.id;
        renderTabs();
        renderEditor();
        save();
      });
      strip.appendChild(tab);
    });
    // the "+" new tab button
    var plus = document.createElement("button");
    plus.id = "new-tab";
    plus.textContent = "+";
    plus.title = "New tab";
    plus.addEventListener("click", newTab);
    strip.appendChild(plus);
  }

  function renderEditor() {
    var t = activeTab();
    var ed = document.getElementById("editor");
    ed.value = t ? t.content : "";
  }

  function newTab() {
    var id = uid();
    state.tabs.push({ id: id, name: "Untitled", content: "" });
    state.active = id;
    renderTabs();
    renderEditor();
    save();
    document.getElementById("editor").focus();
  }

  function closeTab(id) {
    var idx = state.tabs.findIndex(function (t) { return t.id === id; });
    if (idx === -1) return;
    state.tabs.splice(idx, 1);
    if (state.tabs.length === 0) {
      var nid = uid();
      state.tabs.push({ id: nid, name: "Untitled", content: "" });
      state.active = nid;
    } else if (state.active === id) {
      state.active = state.tabs[Math.max(0, idx - 1)].id;
    }
    renderTabs();
    renderEditor();
    save();
  }

  document.getElementById("editor").addEventListener("input", function () {
    var t = activeTab();
    if (!t) return;
    t.content = this.value;
    // derive tab name from first non-empty line
    var firstLine = (this.value.split("\n").find(function (l) { return l.trim().length; }) || "").trim();
    t.name = firstLine ? firstLine.slice(0, 18) : "Untitled";
    var nameEl = document.querySelector('.tab[data-id="' + t.id + '"] .tab-name');
    if (nameEl) nameEl.textContent = t.name;
    save();
  });

  load();
  renderTabs();
  renderEditor();

})();
</script>
</body>
</html>
